    49→/**
    50→ * A single-name credit default swap (CDS).
    51→ * <p>
    52→ * A CDS is a financial instrument where the protection seller agrees to compensate
    53→ * the protection buyer when the reference entity suffers a default.
    54→ * The protection seller is paid premium regularly from the protection buyer until
    55→ * the expiry of the CDS contract or the reference entity defaults before the expiry.
    56→ */
    57→@BeanDefinition
    58→public final class Cds
    59→    implements Product, Resolvable<ResolvedCds>, ImmutableBean, Serializable {
    60→
    61→  /**
    62→   * Whether the CDS is buy or sell.
    63→   * <p>
    64→   * A value of 'Buy' implies buying protection, where the fixed coupon is paid
    65→   * and the protection is received  in the event of default.
    66→   * A value of 'Sell' implies selling protection, where the fixed coupon is received
    67→   * and the protection is paid in the event of default.
    68→   */
    69→  @PropertyDefinition(validate = "notNull")
    70→  private final BuySell buySell;
    71→  /**
    72→   * The legal entity identifier.
    73→   * <p>
    74→   * This identifier is used for the reference legal entity of the CDS.
    75→   */
    76→  @PropertyDefinition(validate = "notNull")
    77→  private final StandardId legalEntityId;
    78→  /**
    79→   * The currency of the CDS.
