   154→  //-------------------------------------------------------------------------
   155→  /**
   156→   * Creates an instance of a standardized CDS.
   157→   * 
   158→   * @param buySell  buy or sell
   159→   * @param legalEntityId  the legal entity ID
   160→   * @param currency  the currency
   161→   * @param notional  the notional
   162→   * @param startDate  the start date
   163→   * @param endDate  the end date
   164→   * @param calendar  the calendar
   165→   * @param fixedRate  the fixed coupon rate
   166→   * @param paymentFrequency  the payment frequency
   167→   * @return the instance
   168→   */
   169→  public static Cds of(
   170→      BuySell buySell,
   171→      StandardId legalEntityId,
   172→      Currency currency,
   173→      double notional,
   174→      LocalDate startDate,
   175→      LocalDate endDate,
   176→      Frequency paymentFrequency,
   177→      HolidayCalendarId calendar,
   178→      double fixedRate) {
   179→
   180→    PeriodicSchedule accrualSchedule = PeriodicSchedule.builder()
   181→        .businessDayAdjustment(BusinessDayAdjustment.of(BusinessDayConventions.FOLLOWING, calendar))
   182→        .startDate(startDate)
   183→        .endDate(endDate)
   184→        .startDateBusinessDayAdjustment(BusinessDayAdjustment.NONE)
   185→        .endDateBusinessDayAdjustment(BusinessDayAdjustment.NONE)
   186→        .frequency(paymentFrequency)
   187→        .rollConvention(RollConventions.NONE)
   188→        .stubConvention(StubConvention.SMART_INITIAL)
   189→        .build();
   190→    return new Cds(
   191→        buySell,
   192→        legalEntityId,
   193→        currency,
   194→        notional,
   195→        accrualSchedule,
   196→        fixedRate,
   197→        DayCounts.ACT_360,
   198→        PaymentOnDefault.ACCRUED_PREMIUM,
   199→        ProtectionStartOfDay.BEGINNING,
   200→        DaysAdjustment.ofCalendarDays(1),
   201→        DaysAdjustment.ofBusinessDays(3, calendar));
   202→  }
   203→
   204→  @ImmutableDefaults
   205→  private static void applyDefaults(Builder builder) {
   206→    builder.dayCount = DayCounts.ACT_360;
   207→    builder.paymentOnDefault = PaymentOnDefault.ACCRUED_PREMIUM;
   208→    builder.protectionStart = ProtectionStartOfDay.BEGINNING;
   209→    builder.stepinDateOffset = DaysAdjustment.ofCalendarDays(1);
   210→  }
   211→
   212→  @ImmutablePreBuild
   213→  private static void preBuild(Builder builder) {
   214→    if (builder.settlementDateOffset == null && builder.paymentSchedule != null) {
   215→      builder.settlementDateOffset =
   216→          DaysAdjustment.ofBusinessDays(3, builder.paymentSchedule.getBusinessDayAdjustment().getCalendar());
   217→    }
   218→  }
