   226→  //-------------------------------------------------------------------------
   227→  @Override
   228→  public ResolvedCds resolve(ReferenceData refData) {
   229→    Schedule adjustedSchedule = paymentSchedule.createSchedule(refData);
   230→    ImmutableList.Builder<CreditCouponPaymentPeriod> accrualPeriods = ImmutableList.builder();
   231→    int nPeriods = adjustedSchedule.size();
   232→    for (int i = 0; i < nPeriods - 1; i++) {
   233→      SchedulePeriod period = adjustedSchedule.getPeriod(i);
   234→      accrualPeriods.add(CreditCouponPaymentPeriod.builder()
   235→          .startDate(period.getStartDate())
   236→          .endDate(period.getEndDate())
   237→          .unadjustedStartDate(period.getUnadjustedStartDate())
   238→          .unadjustedEndDate(period.getUnadjustedEndDate())
   239→          .effectiveStartDate(protectionStart.isBeginning() ? period.getStartDate().minusDays(1) : period.getStartDate())
   240→          .effectiveEndDate(protectionStart.isBeginning() ? period.getEndDate().minusDays(1) : period.getEndDate())
   241→          .paymentDate(period.getEndDate())
   242→          .notional(notional)
   243→          .currency(currency)
   244→          .fixedRate(fixedRate)
   245→          .yearFraction(period.yearFraction(dayCount, adjustedSchedule))
   246→          .build());
   247→    }
   248→    SchedulePeriod lastPeriod = adjustedSchedule.getPeriod(nPeriods - 1);
   249→    LocalDate accEndDate = protectionStart.isBeginning() ? lastPeriod.getEndDate().plusDays(1) : lastPeriod.getEndDate();
   250→    SchedulePeriod modifiedPeriod = lastPeriod.toBuilder().endDate(accEndDate).build();
   251→    accrualPeriods.add(CreditCouponPaymentPeriod.builder()
   252→        .startDate(modifiedPeriod.getStartDate())
   253→        .endDate(modifiedPeriod.getEndDate())
   254→        .unadjustedStartDate(modifiedPeriod.getUnadjustedStartDate())
   255→        .unadjustedEndDate(modifiedPeriod.getUnadjustedEndDate())
   256→        .effectiveStartDate(protectionStart.isBeginning() ? lastPeriod.getStartDate().minusDays(1) : lastPeriod.getStartDate())
   257→        .effectiveEndDate(lastPeriod.getEndDate())
   258→        .paymentDate(paymentSchedule.getBusinessDayAdjustment().adjust(lastPeriod.getEndDate(), refData))
   259→        .notional(notional)
   260→        .currency(currency)
   261→        .fixedRate(fixedRate)
   262→        .yearFraction(modifiedPeriod.yearFraction(dayCount, adjustedSchedule))
   263→        .build());
   264→    ImmutableList<CreditCouponPaymentPeriod> paymentPeriods = accrualPeriods.build();
   265→
   266→    return ResolvedCds.builder()
   267→        .buySell(buySell)
   268→        .legalEntityId(legalEntityId)
   269→        .protectionStart(protectionStart)
   270→        .paymentOnDefault(paymentOnDefault)
   271→        .paymentPeriods(paymentPeriods)
   272→        .protectionEndDate(lastPeriod.getEndDate())
   273→        .settlementDateOffset(settlementDateOffset)
   274→        .stepinDateOffset(stepinDateOffset)
   275→        .dayCount(dayCount)
   276→        .build();
   277→  }
