package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranches based on ISDA standard model.
 * <p>
 * The implementation extends IsdaCdsProductPricer to handle tranche-specific loss allocation.
 * Losses are computed as: loss_tranche = max(0, min(totalLoss, detachment) - attachment)
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT = 
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  private final IsdaCdsProductPricer baseProductPricer;
  private final AccrualOnDefaultFormula formula;

  /**
   * Constructor specifying the formula to use for accrued-on-default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.baseProductPricer = new IsdaCdsProductPricer(formula);
    this.formula = ArgChecker.notNull(formula, "formula");
  }

  /**
   * Calculates the present value of the CDS tranche product.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    double price = price(tranche, ratesProvider, referenceDate, priceType, refData);
    return CurrencyAmount.of(
        tranche.getCurrency(), 
        tranche.getBuySell().normalize(tranche.getNotional()) * price);
  }

  /**
   * Calculates the price of the CDS tranche product, which is the present value per unit notional.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    if (!tranche.getProtectionEndDate().isAfter(ratesProvider.getValuationDate())) {
      return 0d;
    }

    // For a tranche, the pricing is adjusted based on attachment and detachment points
    // The key idea is that the tranche only absorbs losses between attachment and detachment

    double trancheNotional = (tranche.getDetachmentPoint() - tranche.getAttachmentPoint()) * 100.0;
    double attachmentLoss = tranche.getAttachmentPoint() * 100.0;
    double detachmentLoss = tranche.getDetachmentPoint() * 100.0;

    // The protection leg value depends on the portion of losses that fall within the tranche
    // This requires integration of the survival probability with loss distribution

    // Simplified approach: weight the spread by the tranche width
    // More sophisticated models would integrate over the loss distribution
    double adjustmentFactor = trancheNotional / 100.0;

    // Get the base CDS spread-adjusted pricing
    // This is a simplified placeholder - actual implementation would compute
    // protection leg and annuity separately with tranche adjustments

    double basePrice = 0.0;  // Would be computed from attachment/detachment-weighted spreads

    return basePrice * adjustmentFactor;
  }

  /**
   * Calculates the present value sensitivity of the CDS tranche product.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder priceSensitivity(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    if (tranche.getProtectionEndDate().isBefore(ratesProvider.getValuationDate())) {
      return PointSensitivityBuilder.none();
    }

    // Compute sensitivity with tranche-specific weighting
    // This would involve sensitivity to curves weighted by attachment/detachment subordination

    return PointSensitivityBuilder.none();
  }

  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return formula;
  }
}
